  "title": "स्टोरेज लागत विश्लेषण",
  "group": "लागत अनुकूलन",
  "options": [
    {
      "text": "सभी डेटा के लिए S3 Standard"
    },
    {
      "text": "हमेशा सबसे सस्ता स्टोरेज उपयोग करें"
    },
    {
      "text": "एक्सेस पैटर्न के आधार पर स्टोरेज क्लासेज़ को मिलाएँ"
    },
    {
      "text": "सभी कुछ Glacier में स्टोर करें"
    }
  ],
  "questionProse": [
    "1PB डेटा को स्टोर करने के लिए सबसे लागत‑प्रभावी तरीका क्या है, जहाँ 20% रोज़ाना, 30% मासिक और 50% वार्षिक एक्सेस किया जाता है?"
  ],
  "explanationProse": [
    "इष्टतम स्टोरेज रणनीति:\n    - दैनिक एक्सेस के लिए 20% S3 Standard में\n    - मासिक एक्सेस के लिए 30% S3 Standard-IA में\n    - वार्षिक एक्सेस के लिए 50% Glacier में\n\n    यह तरीका लागत को अनुकूलित करता है जबकि उचित एक्सेस पैटर्न बनाए रखता है.\n\n    लागत विचार:\n    - प्रति GB स्टोरेज मूल्य निर्धारण\n    - रिट्रीवल लागत\n    - एक्सेस पैटर्न\n    - ट्रांज़िशन लागत"
  ]
}
